// makeReviewer builds a beadReviewerFunc that always returns the given verdict.
func makeReviewer(verdict Verdict, output string) beadReviewerFunc {
	return beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
		return &ReviewResult{
			Verdict:         verdict,
			RawOutput:       output,
			ReviewerHarness: "claude",
			ReviewerModel:   "claude-opus-4-6",
		}, nil
	})
}

func makeReviewerWithCost(verdict Verdict, output string, costUSD float64) beadReviewerFunc {
	return beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
		return &ReviewResult{
			Verdict:         verdict,
			RawOutput:       output,
			ReviewerHarness: "claude",
			ReviewerModel:   "claude-opus-4-6",
			CostUSD:         costUSD,
		}, nil
	})
}

func TestExecuteBeadWorkerReviewApproveClosesBead(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-review-1",
				ResultRev: "aabbccdd",
			}, nil
		}),
		Reviewer: makeReviewer(VerdictApprove, "### Verdict: APPROVE\n\nAll good."),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, 1, result.Successes)
	assert.Equal(t, 0, result.Failures)

	// Bead must remain closed.
	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, got.Status)

	// Review event must be appended.
	events, err := store.Events(first.ID)
	require.NoError(t, err)
	found := false
	for _, ev := range events {
		if ev.Kind == "review" && ev.Summary == "APPROVE" {
			found = true
		}
	}
	assert.True(t, found, "expected a review:APPROVE event on the bead")

	// Report must carry the verdict.
	require.Len(t, result.Results, 1)
	assert.Equal(t, "APPROVE", result.Results[0].ReviewVerdict)
	assert.Equal(t, ExecuteBeadStatusSuccess, result.Results[0].Status)
}

func TestRunPostMergeReviewChargesReviewCostAndDefersWhenCapTrips(t *testing.T) {
	cases := []struct {
		name         string
		maxCost      float64
		preCost      float64
		reviewCost   float64
		wantDeferred bool
	}{
		{
			name:         "normal fit",
			maxCost:      10.0,
			preCost:      4.0,
			reviewCost:   1.5,
			wantDeferred: false,
		},
		{
			name:         "review tips over budget",
			maxCost:      5.0,
			preCost:      4.0,
			reviewCost:   1.5,
			wantDeferred: true,
		},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			store, first, _ := newExecuteLoopTestStore(t)
			tracker := escalation.NewCostCapTracker(tc.maxCost, func(string) bool { return true })
			tracker.Add("openrouter", tc.preCost)

			reviewer := makeReviewerWithCost(VerdictApprove, "### Verdict: APPROVE\n\nAll good.", tc.reviewCost)
			out := RunPostMergeReview(context.Background(), PostMergeReviewInput{
				Bead: *first,
				Report: ExecuteBeadReport{
					BeadID:    first.ID,
					Status:    ExecuteBeadStatusSuccess,
					SessionID: "sess-review-cost",
					ResultRev: "cafebabe",
					CostUSD:   tc.preCost,
				},
				Reviewer:      reviewer,
				Store:         store,
				ProjectRoot:   t.TempDir(),
				Rcfg:          config.NewTestConfigForLoop(config.TestLoopConfigOpts{Assignee: "worker"}).Resolve(config.TestLoopOverrides(config.TestLoopConfigOpts{Assignee: "worker"})),
				Now:           time.Now,
				Assignee:      "worker",
				ReviewCostCap: tracker,
			})
			require.True(t, out.Approved, "APPROVE review should stay approved even when cost tracking trips")
			require.NoError(t, out.StoreErr)
			assert.InDelta(t, tc.preCost+tc.reviewCost, tracker.Spent(), 1e-9)

			events, err := store.Events(first.ID)
			require.NoError(t, err)
			foundDeferred := false
			for _, ev := range events {
				if ev.Kind == "review-cost-deferred" {
					foundDeferred = true
					assert.Contains(t, ev.Body, "result_rev=cafebabe")
				}
			}
			assert.Equal(t, tc.wantDeferred, foundDeferred)
		})
	}
}

func TestRunPostMergeReviewChargesReviewCostOnReviewerError(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	tracker := escalation.NewCostCapTracker(5.0, func(string) bool { return true })
	tracker.Add("openrouter", 4.0)

	reviewer := beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
		return &ReviewResult{
			Verdict:         VerdictBlock,
			Rationale:       "transport failed",
			ReviewerHarness: "claude",
			ReviewerModel:   "claude-opus-4-6",
			CostUSD:         1.5,
		}, context.DeadlineExceeded
	})

	out := RunPostMergeReview(context.Background(), PostMergeReviewInput{
		Bead: *first,
		Report: ExecuteBeadReport{
			BeadID:    first.ID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-review-error",
			ResultRev: "feedface",
			CostUSD:   4.0,
		},
		Reviewer:      reviewer,
		Store:         store,
		ProjectRoot:   t.TempDir(),
		Rcfg:          config.NewTestConfigForLoop(config.TestLoopConfigOpts{Assignee: "worker"}).Resolve(config.TestLoopOverrides(config.TestLoopConfigOpts{Assignee: "worker"})),
		Now:           time.Now,
		Assignee:      "worker",
		ReviewCostCap: tracker,
	})

	require.False(t, out.Approved, "review error should not approve the bead")
	assert.InDelta(t, 5.5, tracker.Spent(), 1e-9)

	events, err := store.Events(first.ID)
	require.NoError(t, err)
	foundDeferred := false
	for _, ev := range events {
		if ev.Kind == "review-cost-deferred" {
			foundDeferred = true
			assert.Contains(t, ev.Body, "result_rev=feedface")
		}
	}
	assert.True(t, foundDeferred, "expected review cost to be charged and deferred on reviewer error")
}

func TestExecuteBeadWorkerReviewRequestChangesReopensAndCountsFailure(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-review-2",
				ResultRev: "11223344",
			}, nil
		}),
		Reviewer: makeReviewer(VerdictRequestChanges, "### Verdict: REQUEST_CHANGES\n\n- Missing tests."),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, 0, result.Successes)
	assert.Equal(t, 1, result.Failures)
	assert.Equal(t, ExecuteBeadStatusReviewRequestChanges, result.LastFailureStatus)

	// Bead must be re-opened.
	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status, "bead should be reopened after REQUEST_CHANGES")

	// Review findings must appear in bead notes.
	assert.Contains(t, got.Notes, "REQUEST_CHANGES")

	require.Len(t, result.Results, 1)
	assert.Equal(t, "REQUEST_CHANGES", result.Results[0].ReviewVerdict)
	assert.Equal(t, ExecuteBeadStatusReviewRequestChanges, result.Results[0].Status)
}

func TestExecuteBeadWorkerReviewBlockReopensAndFlagsHuman(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-review-3",
				ResultRev: "deadbeef",
			}, nil
		}),
		Reviewer: beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
			return &ReviewResult{
				Verdict:   VerdictBlock,
				Rationale: "AC#3 regression test missing",
				RawOutput: "### Verdict: BLOCK\n\n### Findings\n- AC#3 regression test missing",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, 0, result.Successes)
	assert.Equal(t, 1, result.Failures)
	assert.Equal(t, ExecuteBeadStatusReviewBlock, result.LastFailureStatus)

	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status)
	assert.Contains(t, got.Notes, "REVIEW:BLOCK")
	assert.Contains(t, got.Notes, "AC#3 regression test missing")

	require.Len(t, result.Results, 1)
	assert.Equal(t, "BLOCK", result.Results[0].ReviewVerdict)
	assert.Equal(t, ExecuteBeadStatusReviewBlock, result.Results[0].Status)

	events, err := store.Events(first.ID)
	require.NoError(t, err)
	found := false
	for _, ev := range events {
		if ev.Kind == "execute-bead" && ev.Summary == ExecuteBeadStatusReviewBlock {
			assert.Contains(t, ev.Body, "AC#3 regression test missing")
			found = true
		}
	}
	assert.True(t, found, "expected execute-bead review_block event with rationale")
}

func TestExecuteBeadWorkerReviewBlockWithoutRationaleIsMalfunction(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-review-4",
				ResultRev: "cafed00d",
			}, nil
		}),
		Reviewer: makeReviewer(VerdictBlock, "### Verdict: BLOCK"),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, 0, result.Successes)
	assert.Equal(t, 1, result.Failures)
	assert.Equal(t, ExecuteBeadStatusReviewMalfunction, result.LastFailureStatus)

	got, err := store.Get(first.ID)
	require.NoError(t, err)
	// ddx-e30e60a9 + ddx-738edf47: malformed BLOCK is a reviewer malfunction,
	// not a terminal verdict. The loop refuses to close on a malfunction so
	// a later attempt can retry. Pre-wave-2 behavior closed eagerly before
	// review and left the malformed-BLOCK bead closed — that was the silent
	// false-closure surface these beads eliminate.
	assert.NotEqual(t, bead.StatusClosed, got.Status,
		"malformed BLOCK must not close the bead — closing on reviewer malfunction was the silent-false-closure shape")
	assert.NotContains(t, got.Notes, "REVIEW:BLOCK")

	require.Len(t, result.Results, 1)
	assert.Equal(t, ExecuteBeadStatusReviewMalfunction, result.Results[0].Status)
	assert.Empty(t, result.Results[0].ReviewRationale)
}

func TestDefaultBeadReviewerWritesReviewArtifacts(t *testing.T) {
	projectRoot := t.TempDir()
	cmd := exec.Command("git", "init", projectRoot)
	out, err := cmd.CombinedOutput()
	require.NoError(t, err, string(out))

	store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
	require.NoError(t, store.Init())
	require.NoError(t, os.WriteFile(filepath.Join(projectRoot, "README.md"), []byte("# review test\n"), 0o644))
	require.NoError(t, store.Create(&bead.Bead{

				ProjectRoot:   runtime.ProjectRoot,
				Rcfg:          rcfg,
				NoReview:      runtime.NoReview,
				Log:           runtime.Log,
				Assignee:      assignee,
				Now:           now,
				ReviewCostCap: runtime.ReviewCostCap,
			})
			report = reviewOut.Report
			reviewApproved := reviewOut.Approved
			if reviewOut.StoreErr != nil {
				_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
					return commitOutcomeError(reviewOut.StoreErrOp, assignee, result, reviewOut.StoreErr)
				})
				if ctx.Err() != nil {
					return result, ctx.Err()
				}
				continue
			}

			if reviewApproved {
				result.Successes++
				result.LastSuccessAt = now().UTC()
			} else {
				result.Failures++
				result.LastFailureStatus = report.Status
			}
		} else if attemptOut.Disposition == agenttry.OutcomePark {
			result.Failures++
			result.LastFailureStatus = report.Status
		} else if attemptOut.NoChanges != nil {
			noChanges := attemptOut.NoChanges
			if err := w.Store.Unclaim(candidate.ID); err != nil {
				_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
					return commitOutcomeError("Unclaim", assignee, result, err)
				})
				if ctx.Err() != nil {
					return result, ctx.Err()
				}
				continue
			}
			if noChanges.EventKind != "" {
				_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
					Kind:      noChanges.EventKind,
					Summary:   noChanges.EventKind,
					Body:      noChanges.EventBody,
					Actor:     assignee,
					Source:    "ddx agent execute-loop",
					CreatedAt: now().UTC(),
				})
			}
			if noChanges.Label != "" {
				if err := addBeadLabel(w.Store, candidate.ID, noChanges.Label); err != nil {
					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
						return commitOutcomeError("addBeadLabel", assignee, result, err)
					})
					if ctx.Err() != nil {
						return result, ctx.Err()
					}
					continue
				}
			}
			switch noChanges.Action {
			case agenttry.NoChangesActionCloseAlreadySatisfied:
				// Adjudication confirmed bead is already satisfied.
				// Set the terminal status BEFORE the close so the late
				// executeBeadLoopEvent append captures "already_satisfied"
				// (not "no_changes"), and emit an early execute-bead
				// evidence event so the closure gate accepts even when
				// BaseRev is empty (test fixtures and genuinely-no-commit
				// satisfied beads).
				report.Status = ExecuteBeadStatusAlreadySatisfied
				if noChanges.Evidence != "" {
					// Checker evidence explains why the bead is being closed;
					// it takes precedence over the executor's attempt detail.
					report.Detail = noChanges.Evidence
				}
				_ = w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC()))
				if err := clearExecuteLoopNoChangesMetadata(w.Store, candidate.ID); err != nil {
					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
						return commitOutcomeError("clearExecuteLoopNoChangesMetadata", assignee, result, err)
					})
					if ctx.Err() != nil {
						return result, ctx.Err()
					}
					continue
				}
				if err := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.BaseRev); err != nil {
					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
						return commitOutcomeError("CloseWithEvidence", assignee, result, err)
					})
					if ctx.Err() != nil {
						return result, ctx.Err()
					}
					continue
				}
				result.Successes++
				result.LastSuccessAt = now().UTC()
			case agenttry.NoChangesActionRetryLaterCooldown:
				// Unresolved: suppress immediate retry so the queue can
				// move on to other beads.
				report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
				if noChanges.CooldownEligible && shouldSuppressNoProgress(report) {
					retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
					if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); err != nil {
						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
							return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
						})
						if ctx.Err() != nil {
							return result, ctx.Err()
						}
						continue
					}
					report.RetryAfter = retryAfter.Format(time.RFC3339)
				}
				result.Failures++
				result.LastFailureStatus = report.Status
			default:
				report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
				result.Failures++
				result.LastFailureStatus = report.Status
			}
		} else {
			if attemptOut.Parking == nil && attemptOut.Disposition != agenttry.OutcomePark {
				if err := w.Store.Unclaim(candidate.ID); err != nil {
					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
						return commitOutcomeError("Unclaim", assignee, result, err)
					})
					if ctx.Err() != nil {
						return result, ctx.Err()
					}
					continue
				}
			}
			if report.Status == ExecuteBeadStatusPreservedNeedsReview {
				if err := w.Store.AppendNotes(candidate.ID, preservedNeedsReviewNote(report)); err != nil {
					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
						return commitOutcomeError("AppendNotes", assignee, result, err)
					})
					if ctx.Err() != nil {
						return result, ctx.Err()
					}
					continue
				}
				result.Failures++
				result.LastFailureStatus = report.Status
			} else {
				report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
				if shouldSuppressNoProgress(report) {
					retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
					if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); err != nil {
						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
							return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
						})
						if ctx.Err() != nil {
							return result, ctx.Err()
						}
						continue
					}
					report.RetryAfter = retryAfter.Format(time.RFC3339)
				}
				result.Failures++
				result.LastFailureStatus = report.Status
			}
		}

		result.Results = append(result.Results, report)

		// Skip the late execute-bead append for already-satisfied beads —
		// the satisfied path appends its own terminal event before
		// CloseWithEvidence so the closure gate sees execution evidence.
		// Duplicating it here would yield two identical events.
		if report.Status != ExecuteBeadStatusAlreadySatisfied {
			if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
				_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
					return commitOutcomeError("AppendEvent", assignee, result, err)
				})
				// Event recording failure is non-terminal: log it and continue.
				// result counters were already updated by the outcome block above;
				// do not double-count by re-running the outcome handler.
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "outcome store error (AppendEvent %s): %v (continuing)\n", candidate.ID, err)
				}
				if ctx.Err() == nil {
					_ = w.Store.SetExecutionCooldown(candidate.ID, now().UTC().Add(StoreErrorCooldown), "loop-error", "AppendEvent: "+err.Error())
				}
				if ctx.Err() != nil {
					return result, ctx.Err()
				}
				continue
			}
		}

		// Emit terminal progress phase event.
		terminalPhase := "failed"
		if report.Status == ExecuteBeadStatusSuccess || report.Status == ExecuteBeadStatusAlreadySatisfied {
			terminalPhase = "done"
		} else if report.PreserveRef != "" {
			terminalPhase = "preserved"
		}
		// Use the real attempt_id from the report if available.
		finalAttemptID := report.AttemptID
		if finalAttemptID == "" {
			finalAttemptID = provAttemptID
		}
		phaseSeq++
		emitProgress(runtime.ProgressCh, ProgressEvent{
			EventID:   "evt-" + randomProgressID(),
			AttemptID: finalAttemptID,
			WorkerID:  runtime.WorkerID,
			ProjectID: runtime.ProjectRoot,
			BeadID:    candidate.ID,
			Harness:   harness,
			Model:     model,
			Profile:   profile,
			Phase:     terminalPhase,
			PhaseSeq:  phaseSeq,
			Heartbeat: false,
			TS:        now().UTC(),
			ElapsedMS: now().Sub(runStart).Milliseconds(),
			Message:   report.Detail,
		})

		emit("bead.result", map[string]any{
			"bead_id":              candidate.ID,
			"status":               report.Status,

---REVIEW PATH---
			"status":               report.Status,
			"detail":               report.Detail,
			"session_id":           report.SessionID,
			"result_rev":           report.ResultRev,
			"base_rev":             report.BaseRev,
			"preserve_ref":         report.PreserveRef,
			"no_changes_rationale": report.NoChangesRationale,
			"duration_ms":          now().Sub(runStart).Milliseconds(),
		})

		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "✓ %s → %s\n", candidate.ID, formatLoopResult(report))
		}

		if runtime.Once {
			exitReason = "once_complete"
			return result, nil
		}
	}
}

// emitPickerPrioritySkips fires a picker.priority_skip event when the picker
// chose `chosen` while at least one strictly higher-priority bead was passed
// over (ddx-9d55601f AC #4). Skips at the same priority as `chosen` are NOT
// reported — those are FIFO order or label-filter siblings, not starvation.
//
// The emit is guarded so it costs nothing when the chosen bead is the highest-
// priority bead the picker saw (the common case).
func emitPickerPrioritySkips(emit func(string, map[string]any), chosen bead.Bead, skips []pickerSkip) {
	if len(skips) == 0 {
		return
	}
	var higher []map[string]any
	for _, s := range skips {
		if s.Priority < chosen.Priority {
			higher = append(higher, map[string]any{
				"bead_id":  s.BeadID,
				"priority": s.Priority,
				"reason":   s.Reason,
			})
		}
	}
	if len(higher) == 0 {
		return
	}
	emit("picker.priority_skip", map[string]any{
		"chosen_bead_id":  chosen.ID,
		"chosen_priority": chosen.Priority,
		"skipped":         higher,
	})
}

// pickerSkip records a single bead that the picker passed over while looking
// for the next candidate. It is used to emit a structured picker.priority_skip
// event when a worker claims a lower-priority bead while a higher-priority
// bead was skipped, so future starvation regressions are observable.
//
// Reason values are bounded to the set named in ddx-9d55601f AC #4:
//
//	label_filter, in_attempted, claim_race, eligibility_filter, retry_cooldown
//
// Note: eligibility_filter and retry_cooldown are applied upstream in
// Store.ReadyExecution (so beads filtered for those reasons never reach
// nextCandidate at all). They are part of the reason vocabulary so future
// picker rearrangements can re-emit them without changing the schema.
type pickerSkip struct {
	BeadID   string
	Priority int
	Reason   string
}

func hasGuardSkips(skips []pickerSkip) bool {
	for _, skip := range skips {
		switch skip.Reason {
		case "label_filter", "in_attempted", "claim_race", "eligibility_filter", "retry_cooldown", "target_bead":
			continue
		default:
			return true
		}
	}
	return false
}

// nextCandidate returns the next claimable bead from the execution-ready
// queue along with the list of higher-priority beads it skipped (and the
// reason for each skip). The returned skips slice is only meaningful when
// ok=true: it contains every entry that came BEFORE the chosen candidate
// in the priority-sorted ReadyExecution result.
//
// It delegates filter+sort to PreviewQueue and then additionally filters out
// beads already present in the current drain results slice (which is
// non-deterministic across runs and therefore excluded from the stable
// PreviewQueue surface).
func (w *ExecuteBeadWorker) nextCandidate(ctx context.Context, results []ExecuteBeadReport, guards []work.Guard, labelFilter, targetBeadID string) (bead.Bead, []pickerSkip, bool, error) {
	// Use PreviewQueue for the stable filter+sort logic. Limit=0 returns all
	// entries so we can scan for the first non-attempted candidate.
	entries, err := PreviewQueue(w.Store, PickerFilters{LabelFilter: labelFilter}, 0)
	if err != nil {
		return bead.Bead{}, nil, false, err
	}

	// Rebuild the ready list from the preview entries in picker order so we
	// can apply the per-run drain results slice on top. We need the original
	// bead values for the return; fetch them from ReadyExecution (already
	// ordered).
	ready, err := w.Store.ReadyExecution()
	if err != nil {
		return bead.Bead{}, nil, false, err
	}
	// Index by ID for O(1) lookup.
	byID := make(map[string]bead.Bead, len(ready))
	for _, b := range ready {
		byID[b.ID] = b
	}
	attempted := make(map[string]struct{}, len(results))
	for _, report := range results {
		if report.BeadID != "" {
			attempted[report.BeadID] = struct{}{}
		}
	}

	var skips []pickerSkip
	for _, entry := range entries {
		candidate, ok := byID[entry.BeadID]
		if !ok {
			// Should not happen; skip defensively.
			continue
		}
		if targetBeadID != "" && candidate.ID != targetBeadID {
			skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, Reason: "target_bead"})
			continue
		}
		if _, seen := attempted[candidate.ID]; seen {
			skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, Reason: "in_attempted"})
			continue
		}
		if entry.FilterDecision == FilterDecisionSkipped {
			// PreviewQueue already applied label_filter; record as skip.
			skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, Reason: "label_filter"})
			continue
		}
		allowed := true
		for _, guard := range guards {
			if guard == nil {
				continue
			}
			ok, reason := guard.Allow(ctx, candidate.ID)
			if ok {
				continue
			}
			allowed = false
			if reason != "" {
				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, Reason: reason})
			}
			break
		}
		if !allowed {
			continue
		}
		return candidate, skips, true, nil
	}
	return bead.Bead{}, skips, false, nil
}

// appendLoopRoutingEvidence records a kind:routing evidence event on the bead
// from the executor's ExecuteBeadReport, so that review-outcomes analytics can
// attribute a subsequent review verdict to the originating provider/model tier.
// Best-effort: errors and missing-provider cases are silently ignored.
func appendLoopRoutingEvidence(store BeadEventAppender, beadID string, report ExecuteBeadReport, createdAt time.Time) {
	if store == nil || beadID == "" {
		return
	}
	provider := report.Provider
	if provider == "" {
		provider = report.Harness
	}
	if provider == "" {
		return
	}
	body, err := json.Marshal(map[string]any{
		"resolved_provider": provider,
		"resolved_model":    report.Model,
		"fallback_chain":    []string{},
		"requested_profile": report.RequestedProfile,
		"requested_tier":    report.RequestedTier,
		"resolved_tier":     report.ResolvedTier,
		"escalation_count":  report.EscalationCount,
		"final_tier":        report.FinalTier,
	})
	if err != nil {
		return
	}
	summary := "provider=" + provider
	if report.Model != "" {
		summary += " model=" + report.Model
	}
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "routing",
		Summary:   summary,
		Body:      string(body),
		Actor:     "ddx",
		Source:    "ddx agent execute-loop",
		CreatedAt: createdAt,
	})
}

func appendPreDispatchLintEvent(store BeadEventAppender, beadID string, result LintResult, lintErr error, threshold int, actor string, createdAt time.Time) {
	if store == nil || beadID == "" {
		return
	}
	body := map[string]any{
		"score":           result.Score,
		"rationale":       result.Rationale,
		"suggested_fixes": result.SuggestedFixes,
		"waivers_applied": result.WaiversApplied,
	}
	summary := fmt.Sprintf("score=%d", result.Score)
	if threshold > 0 {
		body["threshold_score"] = threshold
	}
	if lintErr != nil {
		body["warning"] = lintErr.Error()
		summary = "warning " + summary
	} else if threshold > 0 && result.Score < threshold {
		body["dispatch_blocked"] = true
	}
	if encoded, err := json.Marshal(body); err == nil {
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "bead-quality.lint",
			Summary:   summary,
			Body:      string(encoded),
			Actor:     actor,
			Source:    "ddx agent execute-loop",
			CreatedAt: createdAt,
		})
		return

