	assert.Equal(t, spec.Profile, captured[1].Profile,
		"iteration 2 (BLOCK retry): profile pin must propagate")
	assert.Equal(t, spec.Provider, captured[1].Provider,
		"iteration 2 (BLOCK retry): provider pin must propagate")
}

