			results[i], errs[i] = worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
				Once: false,
			})
		}()
	}
	wg.Wait()

	for i, e := range errs {
		require.NoError(t, e, "worker %d returned error", i)
	}

